   533→        function init() {
   534→            const container = document.getElementById('canvasContainer');
   535→            const canvas = document.getElementById('canvas');
   536→
   537→            const width = container.clientWidth;
   538→            const height = container.clientHeight;
   539→
   540→            // Scene
   541→            scene = new THREE.Scene();
   542→            scene.background = new THREE.Color(0xFFFFFF);
   543→
   544→            // Orthographic camera
   545→            camera = new THREE.OrthographicCamera(
   546→                0, width,
   547→                0, -height,
   548→                -1000, 1000
   549→            );
   550→            camera.position.z = 1;
   551→
   552→            // Renderer
   553→            renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true });
   554→            renderer.setSize(width, height);
   555→            renderer.setPixelRatio(window.devicePixelRatio);
   556→
   557→            // Create row lines first (background)
   558→            createRowLines(width);
   559→
   560→            // Create task blocks
   561→            createTaskBlocks();
   562→
   563→            // Generate timeline dates
   564→            generateTimelineDates();
   565→
