   591→        function createTaskBlocks() {
   592→            const blockHeight = CONFIG.ROW_HEIGHT - 6;
   593→
   594→            TASKS.forEach(task => {
   595→                const x = task.start * CONFIG.PIXELS_PER_DAY;
   596→                const y = -(task.train * CONFIG.ROW_HEIGHT + 3);
   597→                const width = (task.end - task.start) * CONFIG.PIXELS_PER_DAY;
   598→
   599→                // Main block
   600→                const geometry = new THREE.PlaneGeometry(width, blockHeight);
   601→                const material = new THREE.MeshBasicMaterial({
