   751→        function changeZoom(factor, centerX, centerY) {
   752→            const oldZoom = zoom;
   753→            zoom = Math.max(0.1, Math.min(5, zoom * factor));
   754→
   755→            if (centerX !== undefined && centerY !== undefined) {
   756→                const container = document.getElementById('canvasContainer');
   757→                const rect = container.getBoundingClientRect();
   758→                const mouseX = centerX - rect.left;
   759→                const mouseY = centerY - rect.top;
   760→
   761→                panOffset.x = mouseX - (mouseX - panOffset.x) * (zoom / oldZoom);
   762→                panOffset.y = mouseY - (mouseY - panOffset.y) * (zoom / oldZoom);
   763→            }
   764→
   765→            updateCamera();
   766→            updateUI();
   767→            render();
   768→        }
   769→
   770→        function onMouseDown(e) {
   771→            isDragging = true;
   772→            lastMousePos = { x: e.clientX, y: e.clientY };
   773→            document.body.style.cursor = 'grabbing';
   774→        }
   775→
   776→        function onMouseMove(e) {
   777→            if (!isDragging) return;
   778→
   779→            const dx = e.clientX - lastMousePos.x;
   780→            const dy = e.clientY - lastMousePos.y;
   781→
   782→            panOffset.x += dx;
   783→            panOffset.y += dy;
   784→
   785→            lastMousePos = { x: e.clientX, y: e.clientY };
   786→
   787→            updateCamera();
   788→            updateUI();
   789→            render();
   790→        }
   791→
   792→        function onMouseUp() {
   793→            isDragging = false;
   794→            document.body.style.cursor = 'default';
   795→        }
   796→
   797→        function onDoubleClick(e) {
   798→            changeZoom(1.5, e.clientX, e.clientY);
   799→        }
   800→
   801→        function resetView() {
   802→            zoom = 1;
   803→            panOffset = { x: 0, y: 0 };
   804→            updateCamera();
   805→            updateUI();
   806→            render();
   807→        }
   808→
   809→        function updateCamera() {
   810→            const container = document.getElementById('canvasContainer');
   811→            const width = container.clientWidth;
   812→            const height = container.clientHeight;
   813→
   814→            camera.left = -panOffset.x / zoom;
   815→            camera.right = (width - panOffset.x) / zoom;
   816→            camera.top = -panOffset.y / zoom;
   817→            camera.bottom = -(height + panOffset.y) / zoom;
   818→            camera.updateProjectionMatrix();
   819→        }
   820→
   821→        function onResize() {
   822→            const container = document.getElementById('canvasContainer');
   823→            const width = container.clientWidth;
   824→            const height = container.clientHeight;
   825→
   826→            renderer.setSize(width, height);
   827→            updateCamera();
   828→            render();
   829→        }
   830→
   831→        function render() {
   832→            renderer.render(scene, camera);
   833→        }
