   404→        function createTaskBlock(x, y, width, taskId, name, hours, isConflict = false) {
   405→            const container = new PIXI.Container();
   406→            const { taskBlockBg, taskBlockBorder, textPrimary, redWarning } = CONFIG.COLORS;
   407→            const blockHeight = CONFIG.DIMENSIONS.taskBlockHeight;
   408→
   409→            // Background with rounded corners
   410→            const bg = new PIXI.Graphics();
   411→            bg.roundRect(0, 0, width - 4, blockHeight, 4);
   412→            bg.fill(isConflict ? 0xFFCDD2 : taskBlockBg);
   413→            bg.stroke({ color: isConflict ? redWarning : taskBlockBorder, width: 1 });
   414→            container.addChild(bg);
   415→
   416→            if (isConflict) {
   417→                // Conflict indicator - red circle with exclamation
   418→                const conflictBg = new PIXI.Graphics();
   419→                conflictBg.circle((width - 4) / 2, blockHeight / 2, 10);
   420→                conflictBg.fill(0xFFEBEE);
   421→                conflictBg.stroke({ color: redWarning, width: 2 });
   422→                container.addChild(conflictBg);
   423→
   424→                const conflictIcon = new PIXI.Text({
   425→                    text: '!',
   426→                    style: { fontFamily: CONFIG.FONTS.regular, fontSize: 14, fontWeight: 'bold', fill: redWarning }
   427→                });
   428→                conflictIcon.anchor.set(0.5);
   429→                conflictIcon.position.set((width - 4) / 2, blockHeight / 2);
   430→                container.addChild(conflictIcon);
   431→            } else {
   432→                // Wrench icon - draw as graphics for cleaner look
   433→                const wrenchIcon = new PIXI.Graphics();
   434→                wrenchIcon.moveTo(8, 8);
   435→                wrenchIcon.lineTo(14, 14);
   436→                wrenchIcon.moveTo(8, 14);
   437→                wrenchIcon.lineTo(14, 8);
   438→                wrenchIcon.moveTo(6, 10);
   439→                wrenchIcon.lineTo(8, 8);
   440→                wrenchIcon.lineTo(8, 12);
   441→                wrenchIcon.stroke({ color: 0x666666, width: 1.5 });
   442→                container.addChild(wrenchIcon);
   443→
   444→                // Task text
   445→                let displayText = `${taskId}: ${name}`;
   446→                if (hours) {
   447→                    displayText += ` (${hours})`;
   448→                }
   449→
   450→                const text = new PIXI.Text({
   451→                    text: displayText,
   452→                    style: { fontFamily: CONFIG.FONTS.regular, fontSize: 11, fill: textPrimary }
   453→                });
   454→                text.position.set(24, 6);
   455→
   456→                // Clip text if too long
   457→                if (text.width > width - 32) {
   458→                    const mask = new PIXI.Graphics();
   459→                    mask.rect(24, 0, width - 36, blockHeight);
   460→                    mask.fill(0xFFFFFF);
   461→                    text.mask = mask;
   462→                    container.addChild(mask);
   463→                }
   464→
   465→                container.addChild(text);
   466→            }
   467→
   468→            container.position.set(x, y);
   469→            return container;
   470→        }
