   475→        function drawTaskConnections(container, baseY) {
   476→            const { sidebarWidth, dayColumnWidth, trainRowHeight, taskBlockHeight } = CONFIG.DIMENSIONS;
   477→
   478→            // Draw connection lines between related tasks based on original image
   479→            const connections = [
   480→                // T002 → T003
   481→                { fromRow: 1, fromDay: 10, toRow: 2, toDay: 9 },
   482→                // T003 → T004 (first task)
   483→                { fromRow: 2, fromDay: 12, toRow: 3, toDay: 9 },
   484→                // T004 → T005
   485→                { fromRow: 3, fromDay: 12, toRow: 4, toDay: 13 },
   486→                // T004 second task → T005/T006
   487→                { fromRow: 3, fromDay: 17, toRow: 4, toDay: 13 },
   488→                { fromRow: 4, fromDay: 17, toRow: 5, toDay: 13 },
   489→                // T005 → T006
   490→                { fromRow: 4, fromDay: 17, toRow: 5, toDay: 13 },
   491→                // T006 → T007
   492→                { fromRow: 5, fromDay: 17, toRow: 6, toDay: 14 },
   493→                // T007 → T008
   494→                { fromRow: 6, fromDay: 17, toRow: 7, toDay: 17 },
   495→                // T009 first → second
   496→                { fromRow: 8, fromDay: 9, toRow: 8, toDay: 17 },
   497→                // T010 tasks
   498→                { fromRow: 9, fromDay: 25, toRow: 9, toDay: 21 },
   499→                // T010 → T011
   500→                { fromRow: 9, fromDay: 25, toRow: 10, toDay: 22 },
   501→                // T011 → T012
   502→                { fromRow: 10, fromDay: 25, toRow: 11, toDay: 25 }
   503→            ];
   504→
   505→            connections.forEach(conn => {
   506→                const startX = sidebarWidth + (conn.fromDay - 1) * dayColumnWidth;
   507→                const startY = baseY + (conn.fromRow * trainRowHeight) + taskBlockHeight / 2 + 3;
   508→                const endX = sidebarWidth + (conn.toDay - 1) * dayColumnWidth;
   509→                const endY = baseY + (conn.toRow * trainRowHeight) + taskBlockHeight / 2 + 3;
   510→
   511→                // Draw the connection line
   512→                const line = new PIXI.Graphics();
   513→                line.moveTo(startX, startY);
   514→                line.lineTo(endX - 5, endY);
   515→                line.stroke({ color: 0x999999, width: 1.5 });
   516→                container.addChild(line);
   517→
   518→                // Draw arrowhead
   519→                const angle = Math.atan2(endY - startY, endX - startX);
   520→                const arrowSize = 6;
   521→
   522→                const arrow = new PIXI.Graphics();
   523→                arrow.moveTo(endX - 5, endY);
   524→                arrow.lineTo(
   525→                    endX - 5 - arrowSize * Math.cos(angle - Math.PI / 6),
   526→                    endY - arrowSize * Math.sin(angle - Math.PI / 6)
   527→                );
   528→                arrow.moveTo(endX - 5, endY);
   529→                arrow.lineTo(
   530→                    endX - 5 - arrowSize * Math.cos(angle + Math.PI / 6),
   531→                    endY - arrowSize * Math.sin(angle + Math.PI / 6)
   532→                );
   533→                arrow.stroke({ color: 0x999999, width: 1.5 });
   534→                container.addChild(arrow);
   535→            });
   536→        }
