   105→
   106→    <script>
   107→        // ========================================
   108→        // CONFIGURATION
   109→        // ========================================
   110→        const CONFIG = {
   111→            TRAINS: 50,
   112→            YEARS: 10,
   113→            PX_PER_DAY: 10,
   114→            PX_PER_TRAIN: 24,
   115→            START_DATE: new Date(2024, 0, 1),
   116→            MIN_ZOOM: 0.1,
   117→            MAX_ZOOM: 5,
   118→            ZOOM_SENSITIVITY: 0.002,
   119→            LOD_THRESHOLDS: {
   120→                MACRO: 0.5,    // Below this = Macro
   121→                MICRO: 2.0    // Above this = Micro
   122→            }
   123→        };
   124→
   125→        // ========================================
   126→        // STATE
   127→        // ========================================
   128→        const state = {
   129→            zoom: 1.0,
   130→            panX: 0,
   131→            panY: 0,
   132→            isDragging: false,
   133→            dragStartX: 0,
   134→            dragStartY: 0,
   135→            lastPanX: 0,
   136→            lastPanY: 0,
   137→            currentLOD: 'MESO',
   138→            tasks: [],
   139→            trains: []
   140→        };
   141→
   142→        // ========================================
   143→        // DOM ELEMENTS
   144→        // ========================================
   145→        const canvas = document.getElementById('mainCanvas');
   146→        const ctx = canvas.getContext('2d');
   147→        const sidebar = document.getElementById('trainList');
   148→        const timelineHeader = document.getElementById('timelineHeader');
   149→        const microOverlay = document.getElementById('microOverlay');
   150→        const zoomLevelEl = document.getElementById('zoomLevel');
   151→        const lodLevelEl = document.getElementById('lodLevel');
   152→        const instructions = document.getElementById('instructions');
   153→
   154→        // ========================================
   155→        // DATA GENERATION
   156→        // ========================================
   157→        function generateData() {
   158→            // Generate trains
   159→            state.trains = Array.from({ length: CONFIG.TRAINS }, (_, i) => ({
   160→                id: `T${String(i + 1).padStart(3, '0')}`,
   161→                name: `Train ${i + 1}`,
   162→                type: i < 30 ? 'ALSTOM' : 'KINKI'
   163→            }));
   164→
   165→            // Generate tasks
   166→            state.tasks = [];
   167→            const taskTypes = ['maintenance', 'overhaul', 'inspection'];
   168→            const colors = ['blue', 'orange', 'gray'];
   169→
   170→            state.trains.forEach((train, trainIndex) => {
   171→                // Generate ~10 tasks per year per train
   172→                for (let year = 0; year < CONFIG.YEARS; year++) {
   173→                    const tasksPerYear = 8 + Math.floor(Math.random() * 5);
   174→                    for (let t = 0; t < tasksPerYear; t++) {
   175→                        const dayOffset = year * 365 + Math.floor(Math.random() * 360);
   176→                        const duration = 2 + Math.floor(Math.random() * 10);
   177→                        const typeIndex = Math.floor(Math.random() * taskTypes.length);
   178→
   179→                        state.tasks.push({
   180→                            id: `${train.id}-${year}-${t}`,
   181→                            trainId: train.id,
   182→                            trainIndex,
   183→                            startDay: dayOffset,
   184→                            duration,
   185→                            type: taskTypes[typeIndex],
   186→                            color: colors[typeIndex],
   187→                            conflict: Math.random() < 0.05 // 5% have conflicts
   188→                        });
   189→                    }
   190→                }
   191→            });
   192→        }
   193→
   194→        // ========================================
   195→        // SIDEBAR
   196→        // ========================================
   197→        function renderSidebar() {
   198→            const visibleTrains = getVisibleTrains();
   199→            sidebar.innerHTML = visibleTrains.map(train => `
   200→                <div class="px-2 py-1 text-[10px] text-gray-700 border-b border-gray-100 truncate"
   201→                     style="height: ${CONFIG.PX_PER_TRAIN * state.zoom}px; line-height: ${CONFIG.PX_PER_TRAIN * state.zoom}px;">
   202→                    ${train.id}
   203→                </div>
   204→            `).join('');
   205→        }
   206→
   207→        function getVisibleTrains() {
   208→            const viewportHeight = canvas.height;
   209→            const startIndex = Math.max(0, Math.floor(-state.panY / (CONFIG.PX_PER_TRAIN * state.zoom)));
   210→            const endIndex = Math.min(CONFIG.TRAINS, startIndex + Math.ceil(viewportHeight / (CONFIG.PX_PER_TRAIN * state.zoom)) + 1);
   211→            return state.trains.slice(startIndex, endIndex);
   212→        }
   213→
   214→        // ========================================
   215→        // TIMELINE HEADER
   216→        // ========================================
   217→        function renderTimelineHeader() {
   218→            const viewportWidth = canvas.width;
   219→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   220→            const startDay = Math.floor(-state.panX / pxPerDay);
   221→            const endDay = startDay + Math.ceil(viewportWidth / pxPerDay) + 1;
   222→
   223→            let html = '';
   224→            const date = new Date(CONFIG.START_DATE);
   225→
   226→            // Determine granularity based on zoom
   227→            let step, format;
   228→            if (state.zoom < 0.3) {
   229→                step = 365; // Years
   230→                format = d => d.getFullYear();
   231→            } else if (state.zoom < 1) {
   232→                step = 30; // Months
   233→                format = d => d.toLocaleDateString('en', { month: 'short', year: '2-digit' });
   234→            } else if (state.zoom < 2) {
   235→                step = 7; // Weeks
   236→                format = d => d.toLocaleDateString('en', { month: 'short', day: 'numeric' });
   237→            } else {
   238→                step = 1; // Days
   239→                format = d => d.toLocaleDateString('en', { weekday: 'short', day: 'numeric' });
   240→            }
   241→
   242→            for (let day = Math.max(0, startDay - step); day < endDay; day += step) {
   243→                date.setTime(CONFIG.START_DATE.getTime() + day * 24 * 60 * 60 * 1000);
   244→                const x = day * pxPerDay + state.panX;
   245→                if (x >= -100 && x < viewportWidth + 100) {
   246→                    html += `<div class="absolute text-[10px] text-gray-500 whitespace-nowrap" style="left: ${x}px;">${format(date)}</div>`;
   247→                }
   248→            }
   249→
   250→            timelineHeader.innerHTML = html;
   251→        }
   252→
   253→        // ========================================
   254→        // LOD DETERMINATION
   255→        // ========================================
   256→        function getLOD() {
   257→            if (state.zoom < CONFIG.LOD_THRESHOLDS.MACRO) return 'MACRO';
   258→            if (state.zoom > CONFIG.LOD_THRESHOLDS.MICRO) return 'MICRO';
   259→            return 'MESO';
   260→        }
   261→
   262→        function updateLODIndicator() {
   263→            const lod = getLOD();
   264→            const colors = {
   265→                MACRO: 'bg-yellow-100 text-yellow-700',
   266→                MESO: 'bg-blue-100 text-blue-700',
   267→                MICRO: 'bg-green-100 text-green-700'
   268→            };
   269→            lodLevelEl.textContent = lod;
   270→            lodLevelEl.className = `font-mono font-semibold px-2 py-0.5 rounded ${colors[lod]}`;
   271→            state.currentLOD = lod;
   272→        }
   273→
   274→        // ========================================
   275→        // CANVAS RENDERING
   276→        // ========================================
   277→        function resizeCanvas() {
   278→            const container = canvas.parentElement;
   279→            canvas.width = container.clientWidth;
   280→            canvas.height = container.clientHeight - 32; // Account for timeline header
   281→            render();
   282→        }
   283→
   284→        function render() {
   285→            ctx.clearRect(0, 0, canvas.width, canvas.height);
   286→
   287→            const lod = getLOD();
   288→
   289→            switch (lod) {
   290→                case 'MACRO':
   291→                    renderMacroLayer();
   292→                    break;
   293→                case 'MESO':
   294→                    renderMesoLayer();
   295→                    break;
   296→                case 'MICRO':
   297→                    renderMicroLayer();
   298→                    break;
   299→            }
   300→
   301→            // Update micro overlay visibility
   302→            microOverlay.style.opacity = lod === 'MICRO' ? '1' : '0';
   303→            microOverlay.style.pointerEvents = lod === 'MICRO' ? 'auto' : 'none';
   304→
   305→            renderSidebar();
   306→            renderTimelineHeader();
   307→            zoomLevelEl.textContent = state.zoom.toFixed(2) + 'x';
   308→            updateLODIndicator();
   309→        }
   310→
   311→        // ========================================
   312→        // MACRO LAYER - Heatmap
   313→        // ========================================
   314→        function renderMacroLayer() {
   315→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   316→            const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
   317→            const cellW = Math.max(4, pxPerDay * 30); // ~1 month per cell
   318→            const cellH = Math.max(4, pxPerTrain);
   319→
   320→            // Create task density map
   321→            const totalDays = CONFIG.YEARS * 365;
   322→            const cols = Math.ceil(totalDays / 30);
   323→            const rows = CONFIG.TRAINS;
   324→
   325→            for (let row = 0; row < rows; row++) {
   326→                for (let col = 0; col < cols; col++) {
   327→                    const x = col * cellW + state.panX;
   328→                    const y = row * cellH + state.panY;
   329→
   330→                    if (x > canvas.width || y > canvas.height || x + cellW < 0 || y + cellH < 0) continue;
   331→
   332→                    // Calculate density based on tasks in this cell
   333→                    const startDay = col * 30;
   334→                    const endDay = startDay + 30;
   335→                    const tasksInCell = state.tasks.filter(t =>
   336→                        t.trainIndex === row &&
   337→                        t.startDay < endDay &&
   338→                        t.startDay + t.duration > startDay
   339→                    ).length;
   340→
   341→                    const density = Math.min(1, tasksInCell / 10);
   342→                    ctx.fillStyle = getHeatColor(density);
   343→                    ctx.fillRect(x, y, cellW - 1, cellH - 1);
   344→                }
   345→            }
   346→        }
   347→
   348→        function getHeatColor(value) {
   349→            // Yellow -> Orange -> Red
   350→            if (value < 0.3) {
   351→                return `rgb(255, ${Math.floor(243 - value * 100)}, ${Math.floor(196 - value * 300)})`;
   352→            } else if (value < 0.6) {
   353→                const t = (value - 0.3) / 0.3;
   354→                return `rgb(255, ${Math.floor(180 - t * 80)}, ${Math.floor(100 - t * 80)})`;
   355→            } else {
   356→                const t = (value - 0.6) / 0.4;
   357→                return `rgb(${Math.floor(255 - t * 55)}, ${Math.floor(100 - t * 70)}, ${Math.floor(20 + t * 20)})`;
   358→            }
   359→        }
   360→
   361→        // ========================================
   362→        // MESO LAYER - DNA Strips
   363→        // ========================================
   364→        function renderMesoLayer() {
   365→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   366→            const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
   367→
   368→            // Draw row backgrounds
   369→            for (let i = 0; i < CONFIG.TRAINS; i++) {
   370→                const y = i * pxPerTrain + state.panY;
   371→                if (y > canvas.height || y + pxPerTrain < 0) continue;
   372→
   373→                ctx.fillStyle = i % 2 === 0 ? '#fafafa' : '#f5f5f5';
   374→                ctx.fillRect(0, y, canvas.width, pxPerTrain);
   375→            }
   376→
   377→            // Draw tasks as blocks
   378→            const visibleTasks = state.tasks.filter(task => {
   379→                const x = task.startDay * pxPerDay + state.panX;
   380→                const y = task.trainIndex * pxPerTrain + state.panY;
   381→                const w = task.duration * pxPerDay;
   382→                return x + w > 0 && x < canvas.width && y + pxPerTrain > 0 && y < canvas.height;
   383→            });
   384→
   385→            visibleTasks.forEach(task => {
   386→                const x = task.startDay * pxPerDay + state.panX;
   387→                const y = task.trainIndex * pxPerTrain + state.panY + 2;
   388→                const w = Math.max(2, task.duration * pxPerDay - 2);
   389→                const h = pxPerTrain - 4;
   390→
   391→                const colors = {
   392→                    blue: ['#3b82f6', '#2563eb'],
   393→                    orange: ['#f59e0b', '#d97706'],
   394→                    gray: ['#9ca3af', '#6b7280']
   395→                };
   396→                const [c1, c2] = colors[task.color] || colors.blue;
   397→
   398→                const gradient = ctx.createLinearGradient(x, y, x + w, y + h);
   399→                gradient.addColorStop(0, c1);
   400→                gradient.addColorStop(1, c2);
   401→
   402→                ctx.fillStyle = gradient;
   403→                ctx.beginPath();
   404→                ctx.roundRect(x, y, w, h, 2);
   405→                ctx.fill();
   406→
   407→                // Conflict indicator
   408→                if (task.conflict) {
   409→                    ctx.strokeStyle = '#ef4444';
   410→                    ctx.lineWidth = 2;
   411→                    ctx.stroke();
   412→                }
   413→            });
   414→        }
   415→
   416→        // ========================================
   417→        // MICRO LAYER - Detailed Cards
   418→        // ========================================
   419→        function renderMicroLayer() {
   420→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   421→            const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
   422→
   423→            // Draw grid
   424→            ctx.strokeStyle = '#e5e7eb';
   425→            ctx.lineWidth = 1;
   426→
   427→            // Vertical lines (days)
   428→            const startDay = Math.floor(-state.panX / pxPerDay);
   429→            const endDay = startDay + Math.ceil(canvas.width / pxPerDay) + 1;
   430→            for (let day = startDay; day < endDay; day++) {
   431→                const x = day * pxPerDay + state.panX;
   432→                ctx.beginPath();
   433→                ctx.moveTo(x, 0);
   434→                ctx.lineTo(x, canvas.height);
   435→                ctx.stroke();
   436→            }
   437→
   438→            // Horizontal lines (trains)
   439→            for (let i = 0; i <= CONFIG.TRAINS; i++) {
   440→                const y = i * pxPerTrain + state.panY;
   441→                if (y < 0 || y > canvas.height) continue;
   442→                ctx.beginPath();
   443→                ctx.moveTo(0, y);
   444→                ctx.lineTo(canvas.width, y);
   445→                ctx.stroke();
   446→            }
   447→
   448→            // Draw tasks with labels
   449→            const visibleTasks = state.tasks.filter(task => {
   450→                const x = task.startDay * pxPerDay + state.panX;
   451→                const y = task.trainIndex * pxPerTrain + state.panY;
   452→                const w = task.duration * pxPerDay;
   453→                return x + w > 0 && x < canvas.width && y + pxPerTrain > 0 && y < canvas.height;
   454→            });
   455→
   456→            visibleTasks.forEach(task => {
   457→                const x = task.startDay * pxPerDay + state.panX + 2;
   458→                const y = task.trainIndex * pxPerTrain + state.panY + 4;
   459→                const w = Math.max(20, task.duration * pxPerDay - 4);
   460→                const h = pxPerTrain - 8;
   461→
   462→                const colors = {
   463→                    blue: ['#3b82f6', '#2563eb'],
   464→                    orange: ['#f59e0b', '#d97706'],
   465→                    gray: ['#9ca3af', '#6b7280']
   466→                };
   467→                const [c1, c2] = colors[task.color] || colors.blue;
   468→
   469→                // Draw card shadow
   470→                ctx.fillStyle = 'rgba(0,0,0,0.1)';
   471→                ctx.beginPath();
   472→                ctx.roundRect(x + 2, y + 2, w, h, 4);
   473→                ctx.fill();
   474→
   475→                // Draw card
   476→                const gradient = ctx.createLinearGradient(x, y, x + w, y + h);
   477→                gradient.addColorStop(0, c1);
   478→                gradient.addColorStop(1, c2);
   479→                ctx.fillStyle = gradient;
   480→                ctx.beginPath();
   481→                ctx.roundRect(x, y, w, h, 4);
   482→                ctx.fill();
   483→
   484→                // Conflict border
   485→                if (task.conflict) {
   486→                    ctx.strokeStyle = '#ef4444';
   487→                    ctx.lineWidth = 2;
   488→                    ctx.shadowColor = '#ef4444';
   489→                    ctx.shadowBlur = 8;
   490→                    ctx.stroke();
   491→                    ctx.shadowBlur = 0;
   492→                }
   493→
   494→                // Draw text if space allows
   495→                if (w > 50) {
   496→                    ctx.fillStyle = '#ffffff';
   497→                    ctx.font = `${Math.min(12, h * 0.6)}px system-ui`;
   498→                    ctx.textBaseline = 'middle';
   499→                    const label = task.type.charAt(0).toUpperCase() + task.type.slice(1);
   500→                    const textWidth = ctx.measureText(label).width;
   501→                    if (textWidth < w - 8) {
   502→                        ctx.fillText(label, x + 6, y + h / 2);
   503→                    }
   504→                }
   505→            });
   506→        }
   507→
   508→        // ========================================
   509→        // EVENT HANDLERS
   510→        // ========================================
   511→        function handleWheel(e) {
   512→            e.preventDefault();
   513→
   514→            const rect = canvas.getBoundingClientRect();
   515→            const mouseX = e.clientX - rect.left;
   516→            const mouseY = e.clientY - rect.top;
   517→
   518→            // Calculate zoom factor
   519→            const delta = -e.deltaY * CONFIG.ZOOM_SENSITIVITY;
   520→            const newZoom = Math.max(CONFIG.MIN_ZOOM, Math.min(CONFIG.MAX_ZOOM, state.zoom * (1 + delta)));
   521→
   522→            // Zoom toward mouse position
   523→            const zoomRatio = newZoom / state.zoom;
   524→            state.panX = mouseX - (mouseX - state.panX) * zoomRatio;
   525→            state.panY = mouseY - (mouseY - state.panY) * zoomRatio;
   526→            state.zoom = newZoom;
   527→
   528→            render();
   529→        }
   530→
   531→        function handleMouseDown(e) {
   532→            state.isDragging = true;
   533→            state.dragStartX = e.clientX;
   534→            state.dragStartY = e.clientY;
   535→            state.lastPanX = state.panX;
   536→            state.lastPanY = state.panY;
   537→            canvas.style.cursor = 'grabbing';
   538→        }
   539→
   540→        function handleMouseMove(e) {
   541→            if (!state.isDragging) return;
   542→
   543→            const dx = e.clientX - state.dragStartX;
   544→            const dy = e.clientY - state.dragStartY;
   545→            state.panX = state.lastPanX + dx;
   546→            state.panY = state.lastPanY + dy;
   547→
   548→            render();
   549→        }
   550→
   551→        function handleMouseUp() {
   552→            state.isDragging = false;
   553→            canvas.style.cursor = 'grab';
   554→        }
   555→
   556→        function handleDoubleClick(e) {
   557→            const rect = canvas.getBoundingClientRect();
   558→            const mouseX = e.clientX - rect.left;
   559→            const mouseY = e.clientY - rect.top;
   560→
   561→            // Zoom in 2x at click location
   562→            const newZoom = Math.min(CONFIG.MAX_ZOOM, state.zoom * 2);
   563→            const zoomRatio = newZoom / state.zoom;
   564→            state.panX = mouseX - (mouseX - state.panX) * zoomRatio;
   565→            state.panY = mouseY - (mouseY - state.panY) * zoomRatio;
   566→            state.zoom = newZoom;
   567→
   568→            render();
   569→        }
   570→
   571→        // Button handlers
   572→        document.getElementById('zoomIn').addEventListener('click', () => {
   573→            const centerX = canvas.width / 2;
   574→            const centerY = canvas.height / 2;
   575→            const newZoom = Math.min(CONFIG.MAX_ZOOM, state.zoom * 1.5);
   576→            const zoomRatio = newZoom / state.zoom;
   577→            state.panX = centerX - (centerX - state.panX) * zoomRatio;
   578→            state.panY = centerY - (centerY - state.panY) * zoomRatio;
   579→            state.zoom = newZoom;
   580→            render();
   581→        });
   582→
   583→        document.getElementById('zoomOut').addEventListener('click', () => {
   584→            const centerX = canvas.width / 2;
   585→            const centerY = canvas.height / 2;
   586→            const newZoom = Math.max(CONFIG.MIN_ZOOM, state.zoom / 1.5);
   587→            const zoomRatio = newZoom / state.zoom;
   588→            state.panX = centerX - (centerX - state.panX) * zoomRatio;
   589→            state.panY = centerY - (centerY - state.panY) * zoomRatio;
   590→            state.zoom = newZoom;
   591→            render();
   592→        });
   593→
   594→        document.getElementById('resetBtn').addEventListener('click', () => {
   595→            state.zoom = 1.0;
   596→            state.panX = 0;
   597→            state.panY = 0;
   598→            render();
   599→        });
   600→
   601→        // ========================================
   602→        // INITIALIZATION
   603→        // ========================================
   604→        function init() {
   605→            generateData();
   606→            resizeCanvas();
   607→
   608→            // Attach event listeners
   609→            canvas.addEventListener('wheel', handleWheel, { passive: false });
   610→            canvas.addEventListener('mousedown', handleMouseDown);
   611→            window.addEventListener('mousemove', handleMouseMove);
   612→            window.addEventListener('mouseup', handleMouseUp);
   613→            canvas.addEventListener('dblclick', handleDoubleClick);
   614→            window.addEventListener('resize', resizeCanvas);
   615→
   616→            // Hide instructions after 5 seconds
   617→            setTimeout(() => {
   618→                instructions.style.opacity = '0';
   619→            }, 5000);
   620→
   621→            render();
   622→        }
   623→
   624→        document.addEventListener('DOMContentLoaded', init);
   625→    </script>
